class Solution:
    def classifyIPv4(self, ip: str) -> str:
        # 使用点号切分字符串，IPv4 地址必须恰好有 4 段
        parts = ip.split(".")
        if len(parts) != 4:
            return "F"

        nums = []

        # 逐段检查是否合法
        for part in parts:
            # 每一段不能为空，例如 "1..1.1" 非法
            if part == "":
                return "F"

            # 每一段必须全部由数字字符组成
            for ch in part:
                if ch < "0" or ch > "9":
                    return "F"

            # 除了数字 0 本身，多位数字不允许出现前导 0
            if len(part) > 1 and part[0] == "0":
                return "F"

            # 转换为整数后，必须在 0 到 255 之间
            value = int(part)
            if value < 0 or value > 255:
                return "F"

            nums.append(value)

        # IP 地址类型只由第一段决定
        first = nums[0]

        if first == 0:
            return "R"
        if 1 <= first <= 126:
            return "A"
        if first == 127:
            return "L"
        if 128 <= first <= 191:
            return "B"
        if 192 <= first <= 223:
            return "C"

        # 按照样例要求，D 类地址输出 F
        if 224 <= first <= 239:
            return "F"

        if 240 <= first <= 255:
            return "E"

        return "F"
```

```java
class Solution {
    public String classifyIPv4(String ip) {
        if (ip == null) {
            return "F";
        }

        // 使用 -1 保留空段，例如 "1.2.3." 会切出末尾空段
        String[] parts = ip.split("\\.", -1);
        if (parts.length != 4) {
            return "F";
        }

        int[] nums = new int[4];

        // 逐段检查是否合法
        for (int i = 0; i < 4; i++) {
            String part = parts[i];

            // 每一段不能为空
            if (part.length() == 0) {
                return "F";
            }

            // 除了数字 0 本身，多位数字不允许出现前导 0
            if (part.length() > 1 && part.charAt(0) == '0') {
                return "F";
            }

            int value = 0;

            // 手动解析整数，避免非法字符导致异常
            for (int j = 0; j < part.length(); j++) {
                char ch = part.charAt(j);

                // 每一段必须全部由数字字符组成
                if (ch < '0' || ch > '9') {
                    return "F";
                }

                value = value * 10 + (ch - '0');

                // IPv4 每段最大值为 255，超过即可直接判非法
                if (value > 255) {
                    return "F";
                }
            }

            nums[i] = value;
        }

        // IP 地址类型只由第一段决定
        int first = nums[0];

        if (first == 0) {
            return "R";
        }
        if (first >= 1 && first <= 126) {
            return "A";
        }
        if (first == 127) {
            return "L";
        }
        if (first >= 128 && first <= 191) {
            return "B";
        }
        if (first >= 192 && first <= 223) {
            return "C";
        }

        // 按照样例要求，D 类地址输出 F
        if (first >= 224 && first <= 239) {
            return "F";
        }

        if (first >= 240 && first <= 255) {
            return "E";
        }

        return "F";
    }
}
