/**
 * classifyIPv4 - 判断 IPv4 地址的分类
 * @param {string} ip IPv4 地址字符串
 * @return {string} 地址类型："A" / "B" / "C" / "E" / "R" / "L" / "F"（不合法）
 */
var classifyIPv4 = function(ip) {
    // 按点号切分，必须恰好 4 段
    var parts = ip.split('.');
    if (parts.length !== 4) return 'F';

    var nums = [];

    // 逐段合法性检查
    for (var i = 0; i < parts.length; i++) {
        var part = parts[i];

        // 空段非法
        if (part.length === 0) return 'F';

        // 非数字字符检查
        for (var j = 0; j < part.length; j++) {
            if (part[j] < '0' || part[j] > '9') return 'F';
        }

        // 前导零检查（单独 "0" 合法，"01" 等非法）
        if (part.length > 1 && part[0] === '0') return 'F';

        // 转为整数并检查范围
        var val = parseInt(part, 10);
        if (val < 0 || val > 255) return 'F';

        nums.push(val);
    }

    // 按第一段分类
    var first = nums[0];

    if (first === 0) return 'R';
    if (first >= 1 && first <= 126) return 'A';
    if (first === 127) return 'L';
    if (first >= 128 && first <= 191) return 'B';
    if (first >= 192 && first <= 223) return 'C';
    // D 类按测试数据要求返回 "F"
    if (first >= 224 && first <= 239) return 'F';
    if (first >= 240 && first <= 255) return 'E';

    return 'F';
};
