/**
 * classifyIPv4 - 判断 IPv4 地址的分类
 * @param ip 输入的IPv4地址字符串，如"192.168.0.1"
 * @return 返回对应的类型："A"、"B"、"C"、"E"、"R"、"L"或"F"（不合法）
 */
char* classifyIPv4(char* ip) {
    int segCount = 0;       // 已完成的段数
    int num = 0;            // 当前段数值
    int numStarted = 0;     // 当前段是否已经开始解析数字
    int firstSeg = -1;      // 第一段的值

    for (int i = 0; ; i++) {
        char ch = ip[i];

        // 遇到分隔符 '.' 或字符串结束符 '\0'
        if (ch == '.' || ch == '\0') {
            // 空段非法（如 "1..1.1" 或 "1."）
            if (!numStarted) return "F";

            segCount++;
            // 记录第一段的值，用于后续分类
            if (firstSeg == -1) firstSeg = num;

            // 每段数值必须在 0~255 范围内
            if (num > 255) return "F";

            // 字符串结束，跳出循环
            if (ch == '\0') break;

            // 重置当前段状态
            num = 0;
            numStarted = 0;
        }
        // 数字字符
        else if (ch >= '0' && ch <= '9') {
            // 段首字符为 '0' 时，后一个字符不能也是数字（防止前导零）
            if (!numStarted && ch == '0' && ip[i + 1] >= '0' && ip[i + 1] <= '9')
                return "F";

            numStarted = 1;
            num = num * 10 + (ch - '0');
        }
        // 非数字字符，直接判非法
        else {
            return "F";
        }
    }

    // 必须恰好 4 段
    if (segCount != 4) return "F";

    // 按第一段范围分类
    if (firstSeg == 0) return "R";
    if (firstSeg >= 1 && firstSeg <= 126) return "A";
    if (firstSeg == 127) return "L";
    if (firstSeg >= 128 && firstSeg <= 191) return "B";
    if (firstSeg >= 192 && firstSeg <= 223) return "C";
    // D 类（224-239）按测试数据要求返回 "F"
    if (firstSeg >= 224 && firstSeg <= 239) return "F";
    if (firstSeg >= 240 && firstSeg <= 255) return "E";

    return "F";
}
